/// meals : [{"idMeal":"53238","strMeal":"Beef pho","strMealAlternate":null,"strCategory":"Beef","strArea":"Vietnamese","strInstructions":"step 1\r\nTip the beef stock along with 500ml of water into a large saucepan. Sit the onion and ginger in a frying pan over a high heat and char on all sides, around 3-5 mins (you can also do this under your grill). Once charred, add to the beef stock. In the same pan, toast the spices for 2-3 mins and once they begin to smell fragrant, add them to the beef stock as well. Bring the stock to the boil, then turn to a simmer and cook for 30mins before straining.\r\n\r\nstep 2\r\nMeanwhile, cut the fat from the steak and wrap in cling film, then put into the freezer for 15 mins – this will make your steak really easy to slice! Slice it thinly, then cover with cling film again and pop into the fridge.\r\n\r\nstep 3\r\nTaste the beef stock and use the palm sugar, fish sauce and soy to season. Cook the noodles according to package instructions and split between two bowls, topping each with the sliced beef. Bring the stock to the boil and then pour into the bowls (the heat will cook the beef). Top each with the spring onions, chilli slices and herbs. Serve with the lime wedges to squeeze over.","strMealThumb":"https://www.themealdb.com/images/media/meals/pbzcrx1763765096.jpg","strTags":null,"strYoutube":"https://www.youtube.com/watch?v=WlosNFMCnE4","strIngredient1":"Beef Stock","strIngredient2":"Onion","strIngredient3":"Ginger","strIngredient4":"Cinnamon Stick","strIngredient5":"Star Anise","strIngredient6":"Coriander Seeds","strIngredient7":"Cloves","strIngredient8":"Sirloin steak","strIngredient9":"Palm Sugar","strIngredient10":"Fish Sauce","strIngredient11":"Soy Sauce","strIngredient12":"Rice Noodles","strIngredient13":"Spring Onions","strIngredient14":"Birds-eye Chillies","strIngredient15":"Basil","strIngredient16":"Coriander","strIngredient17":"Lime","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"1 L ","strMeasure2":"1 large","strMeasure3":"1 Large Chopped","strMeasure4":"1","strMeasure5":"2","strMeasure6":"1 tsp","strMeasure7":"1/2 teaspoon","strMeasure8":"225g","strMeasure9":"1 tsp","strMeasure10":"1 tablespoon","strMeasure11":"1 ½ tbsp","strMeasure12":"200g","strMeasure13":"2 sliced","strMeasure14":"1 small","strMeasure15":"Handful","strMeasure16":"Handful","strMeasure17":"1","strMeasure18":" ","strMeasure19":" ","strMeasure20":" ","strSource":"https://www.bbcgoodfood.com/recipes/beef-pho","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":"2025-11-21 22:40:23"},{"idMeal":"53359","strMeal":"Beef Mandi","strMealAlternate":null,"strCategory":"Beef","strArea":"Indian","strInstructions":"1. Wash the beef and cut into large pieces. Season lightly with salt and turmeric.\r\n2. Heat ghee/oil in a large pot. Add sliced onions and sauté until light golden.\r\n3. Add garlic, green chilies, and tomato; cook until softened.\r\n4. Add the mandi spice mix: coriander, cumin, black pepper, cinnamon, cardamom, cloves, and bay leaves.\r\n5. Add beef pieces and stir on medium heat until the meat is well coated with spices.\r\n6. Pour in water or beef stock. Cover and simmer until beef is tender (about 1.5–2 hours depending on cut).\r\n7. Remove beef carefully and set aside. Strain and measure the broth.\r\n8. Add washed, soaked basmati rice to the broth (usually 1 cup rice = 1.5–2 cups liquid). Adjust seasoning and bring to a boil.\r\n9. Lower heat, cover, and cook the rice until fluffy.\r\n10. Place the beef pieces over the rice and steam on low heat for 10 minutes so flavors combine.\r\n11. Optional: For smoky flavor, place a small hot charcoal on foil in the pot, add 1 tsp butter/oil, immediately cover for 5 minutes. Remove coal before serving.\r\n12. Fluff rice and serve beef mandi with salad or chutney.\r\n","strMealThumb":"https://www.themealdb.com/images/media/meals/1nalo51765188375.jpg","strTags":null,"strYoutube":"","strIngredient1":"Basmati Rice","strIngredient2":"Beef Stock","strIngredient3":"Onion","strIngredient4":"Garlic","strIngredient5":"Green Chilli","strIngredient6":"Tomato","strIngredient7":"Salt","strIngredient8":"Oil","strIngredient9":"Turmeric Powder","strIngredient10":"Cardamom","strIngredient11":"Cloves","strIngredient12":"Bay Leaf","strIngredient13":"","strIngredient14":"","strIngredient15":"","strIngredient16":"","strIngredient17":"","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"1 kg","strMeasure2":"5 Cups","strMeasure3":"2 medium","strMeasure4":"5 chopped cloves","strMeasure5":"2","strMeasure6":"1 small","strMeasure7":"2 1/2 Tsp","strMeasure8":"3  tablespoons","strMeasure9":"1 ½ tsp","strMeasure10":"1/2 tsp","strMeasure11":"1/2 tsp","strMeasure12":"1/2 tsp","strMeasure13":" ","strMeasure14":" ","strMeasure15":" ","strMeasure16":" ","strMeasure17":" ","strMeasure18":" ","strMeasure19":" ","strMeasure20":" ","strSource":"","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":"2025-12-08 10:06:11"},{"idMeal":"53071","strMeal":"Beef Asado","strMealAlternate":null,"strCategory":"Beef","strArea":"Filipino","strInstructions":"0.\tCombine beef, crushed peppercorn, soy sauce, vinegar, dried bay leaves, lemon, and tomato sauce. Mix well. Marinate beef for at least 30 minutes.\r\n1.\tPut the marinated beef in a cooking pot along with remaining marinade. Add water. Let boil.\r\n2.\tAdd Knorr Beef Cube. Stir. Cover the pot and cook for 40 minutes in low heat.\r\n3.\tTurn the beef over. Add tomato paste. Continue cooking until beef tenderizes. Set aside.\r\n4.\tHeat oil in a pan. Fry the potato until it browns. Turn over and continue frying the opposite side. Remove from the pan and place on a clean plate. Do the same with the carrots.\r\n5.\tSave 3 tablespoons of cooking oil from the pan where the potato was fried. Saute onion and garlic until onion softens.\r\n6.\tPour-in the sauce from the beef stew. Let boil. Add the beef. Cook for 2 minutes.\r\n7.\tAdd butter and let it melt. Continue cooking until the sauce reduces to half.","strMealThumb":"https://www.themealdb.com/images/media/meals/pkopc31683207947.jpg","strTags":null,"strYoutube":"https://www.youtube.com/watch?v=lNlK8DVhXXA","strIngredient1":"Beef","strIngredient2":"Beef Stock Concentrate","strIngredient3":"Tomato Puree","strIngredient4":"Water","strIngredient5":"Soy Sauce","strIngredient6":"White Wine Vinegar","strIngredient7":"Pepper","strIngredient8":"Bay Leaf","strIngredient9":"Lemon","strIngredient10":"Tomato Sauce","strIngredient11":"Butter","strIngredient12":"Olive Oil","strIngredient13":"Onion","strIngredient14":"Garlic","strIngredient15":"","strIngredient16":"","strIngredient17":"","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"1.5kg","strMeasure2":"1","strMeasure3":"8 ounces","strMeasure4":"3 cups ","strMeasure5":"6 tablespoons","strMeasure6":"1 tbs","strMeasure7":"2 tbs","strMeasure8":"4","strMeasure9":"1/2 ","strMeasure10":"2 tbs","strMeasure11":"3 tbs","strMeasure12":"1/2 cup ","strMeasure13":"1 chopped","strMeasure14":"4 cloves","strMeasure15":" ","strMeasure16":" ","strMeasure17":" ","strMeasure18":" ","strMeasure19":" ","strMeasure20":" ","strSource":"https://panlasangpinoy.com/beef-asado/","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"52952","strMeal":"Beef Lo Mein","strMealAlternate":null,"strCategory":"Beef","strArea":"Chinese","strInstructions":"STEP 1 - MARINATING THE BEEF\r\nIn a bowl, add the beef, salt, 1 pinch white pepper, 1 Teaspoon sesame seed oil, 1/2 egg, corn starch,1 Tablespoon of oil and mix together.\r\nSTEP 2 - BOILING THE THE NOODLES\r\nIn a 6 qt pot add your noodles to boiling water until the noodles are submerged and boil on high heat for 10 seconds. After your noodles is done boiling strain and cool with cold water.\r\nSTEP 3 - STIR FRY\r\nAdd 2 Tablespoons of oil, beef and cook on high heat untill beef is medium cooked.\r\nSet the cooked beef aside\r\nIn a wok add 2 Tablespoon of oil, onions, minced garlic, minced ginger, bean sprouts, mushrooms, peapods and 1.5 cups of water or until the vegetables are submerged in water.\r\nAdd the noodles to wok\r\nTo make the sauce, add oyster sauce, 1 pinch white pepper, 1 teaspoon sesame seed oil, sugar, and 1 Teaspoon of soy sauce.\r\nNext add the beef to wok and stir-fry","strMealThumb":"https://www.themealdb.com/images/media/meals/1529444830.jpg","strTags":null,"strYoutube":"https://www.youtube.com/watch?v=ZT9LSsNXXe0","strIngredient1":"Beef","strIngredient2":"Salt","strIngredient3":"Pepper","strIngredient4":"Sesame Seed Oil","strIngredient5":"Egg","strIngredient6":"Starch","strIngredient7":"Oil","strIngredient8":"Noodles","strIngredient9":"Onion","strIngredient10":"Minced Garlic","strIngredient11":"Ginger","strIngredient12":"Bean Sprouts","strIngredient13":"Mushrooms","strIngredient14":"Water","strIngredient15":"Oyster Sauce","strIngredient16":"Sugar","strIngredient17":"Soy Sauce","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"1/2 lb","strMeasure2":"pinch","strMeasure3":"pinch","strMeasure4":"2 tsp","strMeasure5":"1/2 ","strMeasure6":"3 tbs","strMeasure7":"5 tbs","strMeasure8":"1/4 lb","strMeasure9":"1/2 cup ","strMeasure10":"1 tsp ","strMeasure11":"1 tsp ","strMeasure12":"1 cup ","strMeasure13":"1 cup ","strMeasure14":"1 cup ","strMeasure15":"1 tbs","strMeasure16":"1 tsp ","strMeasure17":"1 tsp ","strMeasure18":"","strMeasure19":"","strMeasure20":"","strSource":"https://sueandgambo.com/pages/beef-lo-mein","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"53053","strMeal":"Beef Rendang","strMealAlternate":null,"strCategory":"Beef","strArea":"Malaysian","strInstructions":"Chop the spice paste ingredients and then blend it in a food processor until fine.\r\nHeat the oil in a stew pot, add the spice paste, cinnamon, cloves, star anise, and cardamom and stir-fry until aromatic. Add the beef and the pounded lemongrass and stir for 1 minute. Add the coconut milk, tamarind juice, water, and simmer on medium heat, stirring frequently until the meat is almost cooked. Add the kaffir lime leaves, kerisik (toasted coconut), sugar or palm sugar, stirring to blend well with the meat.\r\nLower the heat to low, cover the lid, and simmer for 1 to 1 1/2 hours or until the meat is really tender and the gravy has dried up. Add more salt and sugar to taste. Serve immediately with steamed rice and save some for overnight.","strMealThumb":"https://www.themealdb.com/images/media/meals/bc8v651619789840.jpg","strTags":null,"strYoutube":"https://www.youtube.com/watch?v=Ot-dmfBaZrA","strIngredient1":"Beef","strIngredient2":"Vegetable Oil","strIngredient3":"Cinnamon Stick","strIngredient4":"Cloves","strIngredient5":"Star Anise","strIngredient6":"Cardamom","strIngredient7":"Coconut Cream","strIngredient8":"Water","strIngredient9":"Tamarind Paste","strIngredient10":"Lime","strIngredient11":"Sugar","strIngredient12":"Challots","strIngredient13":"","strIngredient14":"","strIngredient15":"","strIngredient16":"","strIngredient17":"","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"1lb","strMeasure2":"5 tbs","strMeasure3":"1","strMeasure4":"3","strMeasure5":"3","strMeasure6":"3","strMeasure7":"1 cup ","strMeasure8":"1 cup ","strMeasure9":"2 tbs","strMeasure10":"6","strMeasure11":"1 tbs","strMeasure12":"5","strMeasure13":" ","strMeasure14":" ","strMeasure15":" ","strMeasure16":" ","strMeasure17":" ","strMeasure18":" ","strMeasure19":" ","strMeasure20":" ","strSource":"https://rasamalaysia.com/beef-rendang-recipe-rendang-daging/","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"53068","strMeal":"Beef Mechado","strMealAlternate":null,"strCategory":"Beef","strArea":"Filipino","strInstructions":"0.\tMake the beef tenderloin marinade by combining soy sauce, vinegar, ginger, garlic, sesame oil, olive oil, sugar, salt, and ground black pepper in a large bowl. Mix well.\r\n1.\tAdd the cubed beef tenderloin to the bowl with the beef tenderloin marinade. Gently toss to coat the beef. Let it stay for 1 hour.\r\n2.\tUsing a metal or bamboo skewer, assemble the beef kebob by skewering the vegetables and marinated beef tenderloin.\r\n3.\tHeat-up the grill and start grilling the beef kebobs for 3 minutes per side. This will give you a medium beef that is juicy and tender on the inside. Add more time if you want your beef well done, but it will be less tender.\r\n4.\tTransfer to a serving plate. Serve with Saffron rice.\r\n5.\tShare and enjoy!\r\n","strMealThumb":"https://www.themealdb.com/images/media/meals/cgl60b1683206581.jpg","strTags":"Stew,Warming","strYoutube":"https://www.youtube.com/watch?v=jxW3Lj8VjyE","strIngredient1":"Garlic","strIngredient2":"Onion","strIngredient3":"Beef","strIngredient4":"Tomato Puree","strIngredient5":"Water","strIngredient6":"Olive Oil","strIngredient7":"Lemon","strIngredient8":"Potatoes","strIngredient9":"Soy Sauce","strIngredient10":"Black Pepper","strIngredient11":"Bay Leaves","strIngredient12":"Salt","strIngredient13":"","strIngredient14":"","strIngredient15":"","strIngredient16":"","strIngredient17":"","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"3 cloves","strMeasure2":"1 sliced","strMeasure3":"2 Lbs","strMeasure4":"8 ounces","strMeasure5":"1 cup ","strMeasure6":"3 tbs","strMeasure7":"1 Slice","strMeasure8":"1 large","strMeasure9":"1/4 cup","strMeasure10":"1/2 tsp","strMeasure11":"2","strMeasure12":"To taste","strMeasure13":" ","strMeasure14":" ","strMeasure15":" ","strMeasure16":" ","strMeasure17":" ","strMeasure18":" ","strMeasure19":" ","strMeasure20":" ","strSource":"https://panlasangpinoy.com/filipino-pinoy-food-tomato-sauce-beef-mechado-recipe/","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"52950","strMeal":"Szechuan Beef","strMealAlternate":null,"strCategory":"Beef","strArea":"Chinese","strInstructions":"STEP 1 - MARINATING THE BEEF\r\nIn a bowl, add the beef, salt, sesame seed oil, white pepper, egg white, 2 Tablespoon of corn starch and 1 Tablespoon of oil.\r\nSTEP 2 - STIR FRY\r\nFirst Cook the beef by adding 2 Tablespoon of oil until the beef is golden brown.\r\nSet the beef aside\r\nIn a wok add 1 Tablespoon of oil, minced ginger, minced garlic and stir-fry for few seconds.\r\nNext add all of the vegetables and then add sherry cooking wine and 1 cup of water.\r\nTo make the sauce add oyster sauce, hot pepper sauce, and sugar.\r\nadd the cooked beef and 1 spoon of soy sauce\r\nTo thicken the sauce, whisk together 1 Tablespoon of cornstarch and 2 Tablespoon of water in a bowl and slowly add to your stir-fry until it's the right thickness.","strMealThumb":"https://www.themealdb.com/images/media/meals/1529443236.jpg","strTags":null,"strYoutube":"https://www.youtube.com/watch?v=SQGZqZYz7Ms","strIngredient1":"Beef","strIngredient2":"Salt","strIngredient3":"Sesame Seed Oil","strIngredient4":"Pepper","strIngredient5":"Egg White","strIngredient6":"Starch","strIngredient7":"Oil","strIngredient8":"Ginger","strIngredient9":"Garlic","strIngredient10":"Onion","strIngredient11":"Carrots","strIngredient12":"Green Pepper","strIngredient13":"Celery","strIngredient14":"Mushrooms","strIngredient15":"Cooking wine","strIngredient16":"Water","strIngredient17":"Oyster Sauce","strIngredient18":"Hotsauce","strIngredient19":"Sugar","strIngredient20":"Soy Sauce","strMeasure1":"1/2 lb","strMeasure2":"1/2 tsp","strMeasure3":"1 tsp ","strMeasure4":"1 pinch","strMeasure5":"1","strMeasure6":"3 tbs","strMeasure7":"4 tbs","strMeasure8":"1 tsp ","strMeasure9":"1 tsp ","strMeasure10":"3/4 cup ","strMeasure11":"1/2 cup ","strMeasure12":"3/4 cup ","strMeasure13":"1 cup ","strMeasure14":"1 cup ","strMeasure15":"1 tbs","strMeasure16":"1 cup ","strMeasure17":"1 tbs","strMeasure18":"1/2 tsp","strMeasure19":"1 tsp ","strMeasure20":"1 tbs","strSource":"https://sueandgambo.com/pages/szechuan-beef","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"53070","strMeal":"Beef Caldereta","strMealAlternate":null,"strCategory":"Beef","strArea":"Filipino","strInstructions":"0.\tHeat oil in a cooking pot. Saute onion and garlic until onion softens\r\n1.\tAdd beef. Saute until the outer part turns light brown.\r\n2.\tAdd soy sauce. Pour tomato sauce and water. Let boil.\r\n3.\tAdd Knorr Beef Cube. Cover the pressure cooker. Cook for 30 minutes.\r\n4.\tPan-fry carrot and potato until it browns. Set aside.\r\n5.\tAdd chili pepper, liver spread and peanut butter. Stir.\r\n6.\tAdd bell peppers, fried potato and carrot. Cover the pot. Continue cooking for 5 to 7 minutes.\r\n7.\tSeason with salt and ground black pepper. Serve.\r\n","strMealThumb":"https://www.themealdb.com/images/media/meals/41cxjh1683207682.jpg","strTags":null,"strYoutube":"https://www.youtube.com/watch?v=yI7hTz0ft5k","strIngredient1":"Beef","strIngredient2":"Beef Stock","strIngredient3":"Soy Sauce","strIngredient4":"Water","strIngredient5":"Green Pepper","strIngredient6":"Red Pepper","strIngredient7":"Potatoes","strIngredient8":"Carrots","strIngredient9":"Tomato Puree","strIngredient10":"Peanut Butter","strIngredient11":"Chilli Powder","strIngredient12":"Onion","strIngredient13":"Garlic","strIngredient14":"Olive Oil","strIngredient15":"","strIngredient16":"","strIngredient17":"","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"2kg cut cubes","strMeasure2":"1","strMeasure3":"1 tbs","strMeasure4":"2 cups ","strMeasure5":"1 sliced","strMeasure6":"1 sliced","strMeasure7":"1 sliced","strMeasure8":"1 sliced","strMeasure9":"8 ounces","strMeasure10":"3  tablespoons","strMeasure11":"5","strMeasure12":"1 chopped","strMeasure13":"5 cloves","strMeasure14":"3 tbs","strMeasure15":" ","strMeasure16":" ","strMeasure17":" ","strMeasure18":" ","strMeasure19":" ","strMeasure20":" ","strSource":"https://www.kawalingpinoy.com/beef-caldereta/","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"53317","strMeal":"Beef Empanadas","strMealAlternate":null,"strCategory":"Beef","strArea":"Uruguayan","strInstructions":"For the dough place lard, warm water and salt in a large kneading bowl and stir. Add flour and oregano and either knead five miutes by hand or with the kneading function of your machine. Let rest covered for at least half an hour or overnight in the fridge.\r\n\r\n2\r\nFor the filling place tomatoes for about 30 seconds in boiling water, then cool with cold water and peel of skin and cut into cubes. Press garlic through garlic press, cut onions into cubes. Simmer garlic and onions in some olive oil until translucent. Take out onions and garlic and brown the meat at high heat from all sides. Season with all herbs and add the onions, garlic and tomatoes. Let simmer for a few minutes, add salt, pepper and additional spices to taste. You can prepare the meat the night before, chill in fridge if doing so. Boil eggs and also cut into cubes and mix with prepared meat.\r\n\r\n3\r\nCut dough into half and roll out one half thinnly on floured surface. Cut out circles about 12-15cm in diameter. Mine have a diameter of 12.5 cm. Place about 2-4 teaspoons of filling on one circle, put a bit of water all around the edges and fold over the other half so that you get half moons. Be sure to seal the edges with a fork. Repeat until you have no dough and filling left.\r\n\r\n4\r\nMeanwhile preheat oven to 200 degrees Celsius. Brush empanadas with egg wash and bake about 8 empanadas on a baking sheet lined with parchment paper for about 25min or until golden. Serve warm with chimichurri sauce.","strMealThumb":"https://www.themealdb.com/images/media/meals/dxpc7j1764370714.jpg","strTags":null,"strYoutube":"https://www.youtube.com/watch?v=RRNVLC6IAv4","strIngredient1":"Lard","strIngredient2":"Water","strIngredient3":"Salt","strIngredient4":"All purpose flour","strIngredient5":"Tomato","strIngredient6":"Garlic","strIngredient7":"Red Onions","strIngredient8":"Spring Onions","strIngredient9":"Sirloin steak","strIngredient10":"Dried Oregano","strIngredient11":"Paprika","strIngredient12":"Red Pepper Flakes","strIngredient13":"Parsley","strIngredient14":"Salt","strIngredient15":"Pepper","strIngredient16":"Egg","strIngredient17":"Egg Wash","strIngredient18":"Chimichurri sauce","strIngredient19":"","strIngredient20":"","strMeasure1":"60g","strMeasure2":"340g","strMeasure3":"1 tsp","strMeasure4":"600g","strMeasure5":"3","strMeasure6":"1 clove","strMeasure7":"1 large","strMeasure8":"Bunch","strMeasure9":"750g","strMeasure10":"1 tablespoon","strMeasure11":"1 tsp","strMeasure12":"1 tsp","strMeasure13":"1 tsp","strMeasure14":"To taste","strMeasure15":"To taste","strMeasure16":"3","strMeasure17":"Splash","strMeasure18":"Drizzle","strMeasure19":" ","strMeasure20":" ","strSource":"https://jennyisbaking.com/2019/10/25/traditionelle-uruguayische-empanadas/#recipe","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":"2025-11-28 22:56:40"},{"idMeal":"52803","strMeal":"Beef Wellington","strMealAlternate":null,"strCategory":"Beef","strArea":"British","strInstructions":"Put the mushrooms into a food processor with some seasoning and pulse to a rough paste. Scrape the paste into a pan and cook over a high heat for about 10 mins, tossing frequently, to cook out the moisture from the mushrooms. Spread out on a plate to cool.\r\nHeat in a frying pan and add a little olive oil. Season the beef and sear in the hot pan for 30 secs only on each side. (You don't want to cook it at this stage, just colour it). Remove the beef from the pan and leave to cool, then brush all over with the mustard.\r\nLay a sheet of cling film on a work surface and arrange the Parma ham slices on it, in slightly overlapping rows. With a palette knife, spread the mushroom paste over the ham, then place the seared beef fillet in the middle. Keeping a tight hold of the cling film from the edge, neatly roll the Parma ham and mushrooms around the beef to form a tight barrel shape. Twist the ends of the cling film to secure. Chill for 15-20 mins to allow the beef to set and keep its shape.\r\nRoll out the puff pastry on a floured surface to a large rectangle, the thickness of a £1 coin. Remove the cling film from the beef, then lay in the centre. Brush the surrounding pastry with egg yolk. Fold the ends over, the wrap the pastry around the beef, cutting off any excess. Turn over, so the seam is underneath, and place on a baking sheet. Brush over all the pastry with egg and chill for about 15 mins to let the pastry rest.\r\nHeat the oven to 200C, 400F, gas 6.\r\nLightly score the pastry at 1cm intervals and glaze again with beaten egg yolk. Bake for 20 minutes, then lower the oven setting to 180C, 350F, gas 4 and cook for another 15 mins. Allow to rest for 10-15 mins before slicing and serving with the side dishes of your choice. The beef should still be pink in the centre when you serve it.","strMealThumb":"https://www.themealdb.com/images/media/meals/vvpprx1487325699.jpg","strTags":"Meat,Stew","strYoutube":"https://www.youtube.com/watch?v=FS8u1RBdf6I","strIngredient1":"mushrooms","strIngredient2":"English Mustard","strIngredient3":"Olive Oil","strIngredient4":"Beef Fillet","strIngredient5":"Parma ham","strIngredient6":"Puff Pastry","strIngredient7":"Flour","strIngredient8":"Egg Yolks","strIngredient9":null,"strIngredient10":null,"strIngredient11":null,"strIngredient12":null,"strIngredient13":null,"strIngredient14":null,"strIngredient15":null,"strIngredient16":null,"strIngredient17":null,"strIngredient18":null,"strIngredient19":null,"strIngredient20":null,"strMeasure1":"400g","strMeasure2":"1-2tbsp","strMeasure3":"Dash","strMeasure4":"750g piece","strMeasure5":"6-8 slices","strMeasure6":"500g","strMeasure7":"Dusting","strMeasure8":"2 Beaten ","strMeasure9":"","strMeasure10":"","strMeasure11":"","strMeasure12":"","strMeasure13":"","strMeasure14":"","strMeasure15":"","strMeasure16":"","strMeasure17":"","strMeasure18":"","strMeasure19":"","strMeasure20":"","strSource":"http://www.goodtoknow.co.uk/recipes/164868/Gordon-Ramsay-s-beef-Wellington","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"52834","strMeal":"Beef stroganoff","strMealAlternate":null,"strCategory":"Beef","strArea":"Russian","strInstructions":"Heat the olive oil in a non-stick frying pan then add the sliced onion and cook on a medium heat until completely softened, so around 15 mins, adding a little splash of water if they start to stick at all. Crush in the garlic and cook for a 2-3 mins further, then add the butter. Once the butter is foaming a little, add the mushrooms and cook for around 5 mins until completely softened. Season everything well, then tip onto a plate.\r\nTip the flour into a bowl with a big pinch of salt and pepper, then toss the steak in the seasoned flour. Add the steak pieces to the pan, splashing in a little oil if the pan looks particularly dry, and fry for 3-4 mins, until well coloured. Tip the onions and mushrooms back into the pan. Whisk the crème fraîche, mustard and beef stock together, then pour into the pan. Cook over a medium heat for around 5 mins. Scatter with parsley, then serve with pappardelle or rice.","strMealThumb":"https://www.themealdb.com/images/media/meals/svprys1511176755.jpg","strTags":null,"strYoutube":"https://www.youtube.com/watch?v=PQHgQX1Ss74","strIngredient1":"Olive Oil","strIngredient2":"Onions","strIngredient3":"Garlic","strIngredient4":"Butter","strIngredient5":"Mushrooms","strIngredient6":"Beef Fillet","strIngredient7":"Plain Flour","strIngredient8":"Creme Fraiche","strIngredient9":"English Mustard","strIngredient10":"Beef Stock","strIngredient11":"Parsley","strIngredient12":null,"strIngredient13":null,"strIngredient14":null,"strIngredient15":null,"strIngredient16":null,"strIngredient17":null,"strIngredient18":null,"strIngredient19":null,"strIngredient20":null,"strMeasure1":"1 tbls","strMeasure2":"1","strMeasure3":"1 clove","strMeasure4":"1 tbsp","strMeasure5":"250g","strMeasure6":"500g","strMeasure7":"1tbsp","strMeasure8":"150g","strMeasure9":"1 tbsp","strMeasure10":"100ml","strMeasure11":"Topping","strMeasure12":"","strMeasure13":"","strMeasure14":"","strMeasure15":"","strMeasure16":"","strMeasure17":"","strMeasure18":"","strMeasure19":"","strMeasure20":"","strSource":"https://www.bbcgoodfood.com/recipes/beef-stroganoff","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"52876","strMeal":"Minced Beef Pie","strMealAlternate":null,"strCategory":"Beef","strArea":"British","strInstructions":"Preheat the oven to 200C/400F/Gas 6.\r\nHeat the oil in a deep frying pan and fry the beef mince for 4-5 minutes, breaking it up with a wooden spoon as it browns.\r\nAdd the onion and cook for 2-3 minutes, then stir in the tomato purée and cook for 2-3 more minutes. Stir in the flour and cook for a further minute, then add the chopped mushrooms, the stout or beef stock and a couple of dashes of Worcestershire sauce. Bring to the boil, then reduce the heat, cover the pan with a lid and leave to simmer for 20 minutes. Set aside and leave to cool, then turn the meat mixture into a one litre pie dish.\r\nRoll out the pastry on a floured work surface until it is slightly larger than the pie dish. Gently drape the pastry over the dish, pressing firmly onto the edges. Trim, then shape the edges into a fluted shape.\r\nCut some leaf shapes out of the pastry trimmings and decorate the top of the pie, sticking them to the pastry with the beaten egg yolk.\r\nMake three or four slits in the pastry to allow the steam to escape, then brush the pie with the rest of the beaten egg yolk and bake in the oven for 20-25 minutes, or until golden-brown.\r\nTo serve, slice into wedges.","strMealThumb":"https://www.themealdb.com/images/media/meals/xwutvy1511555540.jpg","strTags":"Pie,Meat","strYoutube":"https://www.youtube.com/watch?v=QY47h-uqq5g","strIngredient1":"Vegetable Oil","strIngredient2":"Minced Beef","strIngredient3":"Onion","strIngredient4":"Tomato Puree","strIngredient5":"Plain Flour","strIngredient6":"Mushrooms","strIngredient7":"Beef Stock","strIngredient8":"Worcestershire Sauce","strIngredient9":"Shortcrust Pastry","strIngredient10":"Egg Yolks","strIngredient11":"","strIngredient12":"","strIngredient13":"","strIngredient14":"","strIngredient15":"","strIngredient16":"","strIngredient17":"","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"2 tbs","strMeasure2":"500g","strMeasure3":"1 chopped","strMeasure4":"1 tbls","strMeasure5":"1 ½ tbsp","strMeasure6":"75g","strMeasure7":"250ml","strMeasure8":"Dash","strMeasure9":"400g","strMeasure10":"1","strMeasure11":"","strMeasure12":"","strMeasure13":"","strMeasure14":"","strMeasure15":"","strMeasure16":"","strMeasure17":"","strMeasure18":"","strMeasure19":"","strMeasure20":"","strSource":"https://www.bbc.co.uk/food/recipes/mincedbeefpie_89198","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"52904","strMeal":"Beef Bourguignon","strMealAlternate":null,"strCategory":"Beef","strArea":"French","strInstructions":"Heat a large casserole pan and add 1 tbsp goose fat. Season the beef and fry until golden brown, about 3-5 mins, then turn over and fry the other side until the meat is browned all over, adding more fat if necessary. Do this in 2-3 batches, transferring the meat to a colander set over a bowl when browned.\r\nIn the same pan, fry the bacon, shallots or pearl onions, mushrooms, garlic and bouquet garni until lightly browned. Mix in the tomato purée and cook for a few mins, stirring into the mixture. This enriches the bourguignon and makes a great base for the stew. Then return the beef and any drained juices to the pan and stir through.\r\nPour over the wine and about 100ml water so the meat bobs up from the liquid, but isn’t completely covered. Bring to the boil and use a spoon to scrape the caramelised cooking juices from the bottom of the pan – this will give the stew more flavour.\r\nHeat oven to 150C/fan 130C/gas 2. Make a cartouche: tear off a square of foil slightly larger than the casserole, arrange it in the pan so it covers the top of the stew and trim away any excess foil. Then cook for 3 hrs. If the sauce looks watery, remove the beef and veg with a slotted spoon, and set aside. Cook the sauce over a high heat for a few mins until the sauce has thickened a little, then return the beef and vegetables to the pan.\r\nTo make the celeriac mash, peel the celeriac and cut into cubes. Heat the olive oil in a large frying pan. Tip in the celeriac and fry for 5 mins until it turns golden. Season well with salt and pepper. Stir in the rosemary, thyme, bay and cardamom pods, then pour over 200ml water, enough to nearly cover the celeriac. Turn the heat to low, partially cover the pan and leave to simmer for 25-30 mins.\r\nAfter 25-30 mins, the celeriac should be soft and most of the water will have evaporated. Drain away any remaining water, then remove the herb sprigs, bay and cardamom pods. Lightly crush with a potato masher, then finish with a glug of olive oil and season to taste. Spoon the beef bourguignon into serving bowls and place a large spoonful of the celeriac mash on top. Garnish with one of the bay leaves, if you like.","strMealThumb":"https://www.themealdb.com/images/media/meals/vtqxtu1511784197.jpg","strTags":null,"strYoutube":"https://www.youtube.com/watch?v=SQnr4Z-7rok","strIngredient1":"Goose Fat","strIngredient2":"Beef Shin","strIngredient3":"Bacon","strIngredient4":"Challots","strIngredient5":"Chestnut Mushroom","strIngredient6":"Garlic Clove","strIngredient7":"Bouquet Garni","strIngredient8":"Tomato Puree","strIngredient9":"Red Wine","strIngredient10":"Celeriac","strIngredient11":"Olive Oil","strIngredient12":"Thyme","strIngredient13":"Rosemary","strIngredient14":"Bay Leaf","strIngredient15":"Cardamom","strIngredient16":"","strIngredient17":"","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"3 tsp","strMeasure2":"600g","strMeasure3":"100g ","strMeasure4":"350g","strMeasure5":"250g","strMeasure6":"2 sliced","strMeasure7":"1","strMeasure8":"1 tbs","strMeasure9":"750 ml ","strMeasure10":"600g","strMeasure11":"2 tbs","strMeasure12":"sprigs of fresh","strMeasure13":"sprigs of fresh","strMeasure14":"2","strMeasure15":"4","strMeasure16":"","strMeasure17":"","strMeasure18":"","strMeasure19":"","strMeasure20":"","strSource":"https://www.bbcgoodfood.com/recipes/5032/beef-bourguignon","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"53096","strMeal":"Corned Beef Hash","strMealAlternate":null,"strCategory":"Beef","strArea":"British","strInstructions":"Sauté the onions:\r\nHeat butter in a large skillet (preferably cast iron) on medium heat. Add the onion and cook a few minutes, until translucent.\r\n\r\nAdd the potatoes and corned beef:\r\nMix in the chopped corned beef and potatoes. Spread out evenly over the pan. Increase the heat to high or medium high and press down on the mixture with a metal spatula.\r\n\r\n\r\nCook until browned and then flip:\r\nDo not stir the potatoes and corned beef, but let them brown. If you hear them sizzling, this is good.\r\n\r\nUse a metal spatula to peek underneath and see if they are browning. If nicely browned, use the spatula to flip sections over in the pan so that they brown on the other side. Press down again with the spatula.\r\n\r\nIf there is too much sticking, you can add a little more butter to the pan. Continue to cook in this manner until the potatoes and the corned beef are nicely browned.\r\n\r\nStir in the parsley and season:\r\nRemove from heat, stir in chopped parsley. Add plenty of freshly ground black pepper, and add salt to taste.","strMealThumb":"https://www.themealdb.com/images/media/meals/vz94r81760534692.jpg","strTags":null,"strYoutube":"https://www.youtube.com/watch?v=SPr_UnCrYPg","strIngredient1":"Unsalted Butter","strIngredient2":"Onion","strIngredient3":"Corned Beef","strIngredient4":"Potatoes","strIngredient5":"Kosher Salt","strIngredient6":"Black Pepper","strIngredient7":"Freshly Chopped Parsley","strIngredient8":"","strIngredient9":"","strIngredient10":"","strIngredient11":"","strIngredient12":"","strIngredient13":"","strIngredient14":"","strIngredient15":"","strIngredient16":"","strIngredient17":"","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"3  tablespoons","strMeasure2":"1 medium chopped","strMeasure3":"3 Cups","strMeasure4":"3 chopped","strMeasure5":"Dash","strMeasure6":"Dash","strMeasure7":"Chopped","strMeasure8":" ","strMeasure9":" ","strMeasure10":" ","strMeasure11":" ","strMeasure12":" ","strMeasure13":" ","strMeasure14":" ","strMeasure15":" ","strMeasure16":" ","strMeasure17":" ","strMeasure18":" ","strMeasure19":" ","strMeasure20":" ","strSource":"https://www.simplyrecipes.com/recipes/corned_beef_hash/","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":"2025-10-15 14:19:26"},{"idMeal":"52824","strMeal":"Beef Sunday Roast","strMealAlternate":null,"strCategory":"Beef","strArea":"British","strInstructions":"Cook the Broccoli and Carrots in a pan of boiling water until tender.\r\n\r\nRoast the Beef and Potatoes in the oven for 45mins, the potatoes may need to be checked regularly to not overcook.\r\n\r\nTo make the Yorkshire puddings:\r\nHeat oven to 230C/fan 210C/gas 8. Drizzle a little sunflower oil evenly into 2 x 4-hole Yorkshire pudding tins or a 12-hole non-stick muffin tin and place in the oven to heat through\r\nTo make the batter, tip 140g plain flour into a bowl and beat in four eggs until smooth. Gradually add 200ml milk and carry on beating until the mix is completely lump-free. Season with salt and pepper. Pour the batter into a jug, then remove the hot tins from the oven. Carefully and evenly pour the batter into the holes. Place the tins back in the oven and leave undisturbed for 20-25 mins until the puddings have puffed up and browned. Serve immediately.\r\n\r\nPlate up and add the Gravy as desired.","strMealThumb":"https://www.themealdb.com/images/media/meals/ssrrrs1503664277.jpg","strTags":"MainMeal","strYoutube":"https://www.youtube.com/watch?v=2l3-dBdNehY","strIngredient1":"Beef","strIngredient2":"Broccoli","strIngredient3":"Potatoes","strIngredient4":"Carrots","strIngredient5":"plain flour","strIngredient6":"Eggs","strIngredient7":"milk","strIngredient8":"sunflower oil","strIngredient9":null,"strIngredient10":null,"strIngredient11":null,"strIngredient12":null,"strIngredient13":null,"strIngredient14":null,"strIngredient15":null,"strIngredient16":null,"strIngredient17":null,"strIngredient18":null,"strIngredient19":null,"strIngredient20":null,"strMeasure1":"8 slices","strMeasure2":"12 florets","strMeasure3":"1 Packet","strMeasure4":"1 Packet","strMeasure5":"140g","strMeasure6":"4","strMeasure7":"200ml","strMeasure8":"drizzle (for cooking)","strMeasure9":"","strMeasure10":"","strMeasure11":"","strMeasure12":"","strMeasure13":"","strMeasure14":"","strMeasure15":"","strMeasure16":"","strMeasure17":"","strMeasure18":"","strMeasure19":"","strMeasure20":"","strSource":"https://www.bbcgoodfood.com/recipes/9020/best-yorkshire-puddings","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"53112","strMeal":"Kenyan Beef Curry","strMealAlternate":null,"strCategory":"Beef","strArea":"Kenyan","strInstructions":"Bring the 4 cups of water to a boil in a Dutch oven or soup pot. Add the beef, garlic, and ginger, and stir well. Bring to a gentle simmer, cover, and cook, stirring occasionally, for 20 minutes. If you get any foamy scum on the top, not to worry, simply spoon it away or stir it back in.\r\nRemove from the heat, and drain, but reserve the excess water for later.\r\nReturn the pot or Dutch oven to medium heat with the 2 tablespoons of cooking oil. Once the oil is shimmering, add the onions and cook, stirring occasionally, until softened, 5 to 7 minutes.\r\nAdd the tomatoes to the onions, and continue cooking, stirring occasionally, until the tomatoes are falling apart, 3 to 5 minutes.\r\nAdd the drained beef to the tomato and onion mixture, and stir well. Continue cooking over medium heat for 5 minutes, stirring occasionally.\r\nAdd the paprika, pepper, curry powder, tomato paste, and salt to taste, and stir well.\r\nAdd back the excess water that was used for cooking the beef, along with enough extra water to cover. Bring to a boil, reduce heat, and simmer, uncovered, stirring occasionally, for about 1 hour, or until the meat is tender and the sauce is thickened. Add additional water if your beef curry begins to dry and stick, or if would like your curry to have more of a soupy consistency.\r\nWhen the beef curry is ready, remove from the heat, give it a taste, and adjust the seasonings as desired. Garnish with fresh chilis and cilantro.","strMealThumb":"https://www.themealdb.com/images/media/meals/lqampv1762325397.jpg","strTags":null,"strYoutube":"https://www.youtube.com/watch?v=NxrOueTLiqA","strIngredient1":"Water","strIngredient2":"Sirloin Steak tips","strIngredient3":"Garlic Clove","strIngredient4":"Ground Ginger","strIngredient5":"Oil","strIngredient6":"Red Onions","strIngredient7":"Tomato","strIngredient8":"Paprika","strIngredient9":"Black Pepper","strIngredient10":"Curry Powder","strIngredient11":"Tomato Puree","strIngredient12":"Salt","strIngredient13":"Chilli","strIngredient14":"Cilantro","strIngredient15":"","strIngredient16":"","strIngredient17":"","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"4 cups ","strMeasure2":"2 Lbs","strMeasure3":"4","strMeasure4":"2 teaspoons","strMeasure5":"2 tblsp ","strMeasure6":"2 medium","strMeasure7":"4","strMeasure8":"2 tblsp","strMeasure9":"1/2 teaspoon","strMeasure10":"2 teaspoons","strMeasure11":"4 tablespoons","strMeasure12":"Dash","strMeasure13":"1","strMeasure14":"Leaves","strMeasure15":" ","strMeasure16":" ","strMeasure17":" ","strMeasure18":" ","strMeasure19":" ","strMeasure20":" ","strSource":"https://tasteoftheplace.com/kenyan-beef-curry/","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":"2025-11-05 05:25:07"},{"idMeal":"52873","strMeal":"Beef Dumpling Stew","strMealAlternate":null,"strCategory":"Beef","strArea":"British","strInstructions":"Preheat the oven to 180C/350F/Gas 4.\r\n\r\nFor the beef stew, heat the oil and butter in an ovenproof casserole and fry the beef until browned on all sides.\r\n\r\nSprinkle over the flour and cook for a further 2-3 minutes.\r\n\r\nAdd the garlic and all the vegetables and fry for 1-2 minutes.\r\n\r\nStir in the wine, stock and herbs, then add the Worcestershire sauce and balsamic vinegar, to taste. Season with salt and freshly ground black pepper.\r\n\r\nCover with a lid, transfer to the oven and cook for about two hours, or until the meat is tender.\r\n\r\nFor the dumplings, sift the flour, baking powder and salt into a bowl.\r\nAdd the suet and enough water to form a thick dough.\r\n\r\nWith floured hands, roll spoonfuls of the dough into small balls.\r\n\r\nAfter two hours, remove the lid from the stew and place the balls on top of the stew. Cover, return to the oven and cook for a further 20 minutes, or until the dumplings have swollen and are tender. (If you prefer your dumplings with a golden top, leave the lid off when returning to the oven.)\r\n\r\nTo serve, place a spoonful of mashed potato onto each of four serving plates and top with the stew and dumplings. Sprinkle with chopped parsley.","strMealThumb":"https://www.themealdb.com/images/media/meals/uyqrrv1511553350.jpg","strTags":"Stew,Baking","strYoutube":"https://www.youtube.com/watch?v=6NgheY-r5t0","strIngredient1":"Olive Oil","strIngredient2":"Butter","strIngredient3":"Beef","strIngredient4":"Plain Flour","strIngredient5":"Garlic","strIngredient6":"Onions","strIngredient7":"Celery","strIngredient8":"Carrots","strIngredient9":"Leek","strIngredient10":"Swede","strIngredient11":"Red Wine","strIngredient12":"Beef Stock","strIngredient13":"Bay Leaf","strIngredient14":"Thyme","strIngredient15":"Parsley","strIngredient16":"Plain Flour","strIngredient17":"Baking Powder","strIngredient18":"Suet","strIngredient19":"Water","strIngredient20":null,"strMeasure1":"2 tbs","strMeasure2":"25g","strMeasure3":"750g","strMeasure4":"2 tblsp ","strMeasure5":"2 cloves minced","strMeasure6":"175g","strMeasure7":"150g","strMeasure8":"150g","strMeasure9":"2 chopped","strMeasure10":"200g","strMeasure11":"150ml","strMeasure12":"500g","strMeasure13":"2","strMeasure14":"3 tbs","strMeasure15":"3 tblsp chopped","strMeasure16":"125g","strMeasure17":"1 tsp ","strMeasure18":"60g","strMeasure19":"Splash","strMeasure20":"","strSource":"https://www.bbc.co.uk/food/recipes/beefstewwithdumpling_87333","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"53199","strMeal":"Thai beef stir-fry","strMealAlternate":null,"strCategory":"Beef","strArea":"Thai","strInstructions":"step 1\r\nHeat a wok or large frying pan until smoking hot. Pour in the oil and swirl around the pan, then tip in the beef strips and chilli. Cook, stirring all the time, until the meat is lightly browned, about 3 mins, then pour over the oyster sauce. Cook until heated through and the sauce coats the meat. stir in the basil leaves and serve with plain rice.","strMealThumb":"https://www.themealdb.com/images/media/meals/kyuxew1763479470.jpg","strTags":null,"strYoutube":"https://www.youtube.com/watch?v=N3OI_7zu5sA","strIngredient1":"Vegetable Oil","strIngredient2":"Beef","strIngredient3":"Red Chilli","strIngredient4":"Oyster Sauce","strIngredient5":"Basil Leaves","strIngredient6":"","strIngredient7":"","strIngredient8":"","strIngredient9":"","strIngredient10":"","strIngredient11":"","strIngredient12":"","strIngredient13":"","strIngredient14":"","strIngredient15":"","strIngredient16":"","strIngredient17":"","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"2 tbsp","strMeasure2":"400g","strMeasure3":"1 sliced","strMeasure4":"2 tblsp ","strMeasure5":"Handful","strMeasure6":" ","strMeasure7":" ","strMeasure8":" ","strMeasure9":" ","strMeasure10":" ","strMeasure11":" ","strMeasure12":" ","strMeasure13":" ","strMeasure14":" ","strMeasure15":" ","strMeasure16":" ","strMeasure17":" ","strMeasure18":" ","strMeasure19":" ","strMeasure20":" ","strSource":"https://www.bbcgoodfood.com/recipes/thai-beef-stir-fry","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":"2025-11-18 15:19:25"},{"idMeal":"52826","strMeal":"Braised Beef Chilli","strMealAlternate":null,"strCategory":"Beef","strArea":"Mexican","strInstructions":"Preheat the oven to 120C/225F/gas mark 1.\r\n\r\nTake the meat out of the fridge to de-chill. Pulse the onions and garlic in a food processor until finely chopped. Heat 2 tbsp olive oil in a large casserole and sear the meat on all sides until golden.\r\n\r\nSet to one side and add another small slug of oil to brown the chorizo. Remove and add the onion and garlic, spices, herbs and chillies then cook until soft in the chorizo oil. Season with salt and pepper and add the vinegar, tomatoes, ketchup and sugar.\r\n\r\nPut all the meat back into the pot with 400ml water (or red wine if you prefer), bring up to a simmer and cook, covered, in the low oven.\r\n\r\nAfter 2 hours, check the meat and add the beans. Cook for a further hour and just before serving, pull the meat apart with a pair of forks.","strMealThumb":"https://www.themealdb.com/images/media/meals/uuqvwu1504629254.jpg","strTags":null,"strYoutube":"https://www.youtube.com/watch?v=z4kSoJgsu6Y","strIngredient1":"Beef","strIngredient2":"Onions","strIngredient3":"Garlic","strIngredient4":"Olive oil","strIngredient5":"Chorizo","strIngredient6":"Cumin","strIngredient7":"Allspice","strIngredient8":"Cloves","strIngredient9":"Cinnamon stick","strIngredient10":"Bay Leaves","strIngredient11":"Oregano","strIngredient12":"Ancho Chillies","strIngredient13":"Balsamic Vinegar","strIngredient14":"Plum Tomatoes","strIngredient15":"Tomato Ketchup","strIngredient16":"Dark Brown Sugar","strIngredient17":"Borlotti Beans","strIngredient18":null,"strIngredient19":null,"strIngredient20":null,"strMeasure1":"1kg","strMeasure2":"3","strMeasure3":"4 cloves","strMeasure4":"Dash","strMeasure5":"300g","strMeasure6":"2 tsp","strMeasure7":"2 tsp","strMeasure8":"1 tsp","strMeasure9":"1 large","strMeasure10":"3","strMeasure11":"2 tsp dried","strMeasure12":"2 ancho","strMeasure13":"3 tbsp","strMeasure14":"2 x 400g","strMeasure15":"2 tbsp","strMeasure16":"2 tbsp","strMeasure17":"2 x 400g tins","strMeasure18":"","strMeasure19":"","strMeasure20":"","strSource":"http://www.telegraph.co.uk/food-and-drink/recipes/braised-beef-chilli-con-carne/","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"52827","strMeal":"Massaman Beef curry","strMealAlternate":null,"strCategory":"Beef","strArea":"Thai","strInstructions":"Heat oven to 200C/180C fan/gas 6, then roast the peanuts on a baking tray for 5 mins until golden brown. When cool enough to handle, roughly chop. Reduce oven to 180C/160C fan/gas 4.\r\nHeat 2 tbsp coconut cream in a large casserole dish with a lid. Add the curry paste and fry for 1 min, then stir in the beef and fry until well coated and sealed. Stir in the rest of the coconut with half a can of water, the potatoes, onion, lime leaves, cinnamon, tamarind, sugar, fish sauce and most of the peanuts. Bring to a simmer, then cover and cook for 2 hrs in the oven until the beef is tender.\r\nSprinkle with sliced chilli and the remaining peanuts, then serve straight from the dish with jasmine rice.","strMealThumb":"https://www.themealdb.com/images/media/meals/tvttqv1504640475.jpg","strTags":"Curry","strYoutube":"https://www.youtube.com/watch?v=mVxgZSCU9_g","strIngredient1":"Peanuts","strIngredient2":"Coconut cream","strIngredient3":"Massaman curry paste","strIngredient4":"Beef","strIngredient5":"Potatoes","strIngredient6":"Onion","strIngredient7":"Lime","strIngredient8":"Cinnamon stick","strIngredient9":"Tamarind paste","strIngredient10":"Brown sugar","strIngredient11":"Fish Sauce","strIngredient12":"chilli","strIngredient13":"Jasmine Rice","strIngredient14":null,"strIngredient15":null,"strIngredient16":null,"strIngredient17":null,"strIngredient18":null,"strIngredient19":null,"strIngredient20":null,"strMeasure1":"85g","strMeasure2":"400ml can","strMeasure3":"4 tbsp","strMeasure4":"600g stewing cut into strips","strMeasure5":"450g waxy","strMeasure6":"1 cut thin wedges","strMeasure7":"4 leaves","strMeasure8":"1","strMeasure9":"1 tbsp","strMeasure10":"1 tbsp palm or soft light","strMeasure11":"1 tbsp","strMeasure12":"1 red deseeded and finely sliced, to serve","strMeasure13":"to serve","strMeasure14":"","strMeasure15":"","strMeasure16":"","strMeasure17":"","strMeasure18":"","strMeasure19":"","strMeasure20":"","strSource":"https://www.bbcgoodfood.com/recipes/420631/beef-massaman-curry","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"52878","strMeal":"Beef and Oyster pie","strMealAlternate":null,"strCategory":"Beef","strArea":"British","strInstructions":"Season the beef cubes with salt and black pepper. Heat a tablespoon of oil in the frying pan and fry the meat over a high heat. Do this in three batches so that you don’t overcrowd the pan, transferring the meat to a large flameproof casserole dish once it is browned all over. Add extra oil if the pan seems dry.\r\nIn the same pan, add another tablespoon of oil and cook the shallots for 4-5 minutes, then add the garlic and fry for 30 seconds. Add the bacon and fry until slightly browned. Transfer the onion and bacon mixture to the casserole dish and add the herbs.\r\nPreheat the oven to 180C/350F/Gas 4.\r\nPour the stout into the frying pan and bring to the boil, stirring to lift any stuck-on browned bits from the bottom of the pan. Pour the stout over the beef in the casserole dish and add the stock. Cover the casserole and place it in the oven for 1½-2 hours, or until the beef is tender and the sauce is reduced.\r\nSkim off any surface fat, taste and add salt and pepper if necessary, then stir in the cornflour paste. Put the casserole dish on the hob – don’t forget that it will be hot – and simmer for 1-2 minutes, stirring, until thickened. Leave to cool.\r\nIncrease the oven to 200C/400F/Gas 6. To make the pastry, put the flour and salt in a very large bowl. Grate the butter and stir it into the flour in three batches. Gradually add 325ml/11fl oz cold water – you may not need it all – and stir with a round-bladed knife until the mixture just comes together. Knead the pastry lightly into a ball on a lightly floured surface and set aside 250g/9oz for the pie lid.\r\nRoll the rest of the pastry out until about 2cm/¾in larger than the dish you’re using. Line the dish with the pastry then pile in the filling, tucking the oysters in as well. Brush the edge of the pastry with beaten egg.\r\nRoll the remaining pastry until slightly larger than your dish and gently lift over the filling, pressing the edges firmly to seal, then trim with a sharp knife. Brush with beaten egg to glaze. Put the dish on a baking tray and bake for 25-30 minutes, or until the pastry is golden-brown and the filling is bubbling.","strMealThumb":"https://www.themealdb.com/images/media/meals/wrssvt1511556563.jpg","strTags":"Pie","strYoutube":"https://www.youtube.com/watch?v=ONX74yP6JnI","strIngredient1":"Beef","strIngredient2":"Olive Oil","strIngredient3":"Shallots","strIngredient4":"Garlic","strIngredient5":"Bacon","strIngredient6":"Thyme","strIngredient7":"Bay Leaf","strIngredient8":"Stout","strIngredient9":"Beef Stock","strIngredient10":"Corn Flour","strIngredient11":"Oysters","strIngredient12":"Plain Flour","strIngredient13":"Salt","strIngredient14":"Butter","strIngredient15":"Eggs","strIngredient16":"","strIngredient17":"","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"900g","strMeasure2":"3 tbs","strMeasure3":"3","strMeasure4":"2 cloves minced","strMeasure5":"125g","strMeasure6":"1 tbs chopped","strMeasure7":"2","strMeasure8":"330ml","strMeasure9":"400ml","strMeasure10":"2 tbs","strMeasure11":"8","strMeasure12":"400g","strMeasure13":"pinch","strMeasure14":"250g","strMeasure15":"To Glaze","strMeasure16":"","strMeasure17":"","strMeasure18":"","strMeasure19":"","strMeasure20":"","strSource":"https://www.bbc.co.uk/food/recipes/beef_and_oyster_pie_65230","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"52874","strMeal":"Beef and Mustard Pie","strMealAlternate":null,"strCategory":"Beef","strArea":"British","strInstructions":"Preheat the oven to 150C/300F/Gas 2.\r\nToss the beef and flour together in a bowl with some salt and black pepper.\r\nHeat a large casserole until hot, add half of the rapeseed oil and enough of the beef to just cover the bottom of the casserole.\r\nFry until browned on each side, then remove and set aside. Repeat with the remaining oil and beef.\r\nReturn the beef to the pan, add the wine and cook until the volume of liquid has reduced by half, then add the stock, onion, carrots, thyme and mustard, and season well with salt and pepper.\r\nCover with a lid and place in the oven for two hours.\r\nRemove from the oven, check the seasoning and set aside to cool. Remove the thyme.\r\nWhen the beef is cool and you're ready to assemble the pie, preheat the oven to 200C/400F/Gas 6.\r\nTransfer the beef to a pie dish, brush the rim with the beaten egg yolks and lay the pastry over the top. Brush the top of the pastry with more beaten egg.\r\nTrim the pastry so there is just enough excess to crimp the edges, then place in the oven and bake for 30 minutes, or until the pastry is golden-brown and cooked through.\r\nFor the green beans, bring a saucepan of salted water to the boil, add the beans and cook for 4-5 minutes, or until just tender.\r\nDrain and toss with the butter, then season with black pepper.\r\nTo serve, place a large spoonful of pie onto each plate with some green beans alongside.","strMealThumb":"https://www.themealdb.com/images/media/meals/sytuqu1511553755.jpg","strTags":"Meat,Pie","strYoutube":"https://www.youtube.com/watch?v=nMyBC9staMU","strIngredient1":"Beef","strIngredient2":"Plain Flour","strIngredient3":"Rapeseed Oil","strIngredient4":"Red Wine","strIngredient5":"Beef Stock","strIngredient6":"Onion","strIngredient7":"Carrots","strIngredient8":"Thyme","strIngredient9":"Mustard","strIngredient10":"Egg Yolks","strIngredient11":"Puff Pastry","strIngredient12":"Green Beans","strIngredient13":"Butter","strIngredient14":"Salt","strIngredient15":"Pepper","strIngredient16":"","strIngredient17":"","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"1kg","strMeasure2":"2 tbs","strMeasure3":"2 tbs","strMeasure4":"200ml","strMeasure5":"400ml","strMeasure6":"1 finely sliced","strMeasure7":"2 chopped","strMeasure8":"3 sprigs","strMeasure9":"2 tbs","strMeasure10":"2 free-range","strMeasure11":"400g","strMeasure12":"300g","strMeasure13":"25g","strMeasure14":"pinch","strMeasure15":"pinch","strMeasure16":"","strMeasure17":"","strMeasure18":"","strMeasure19":"","strMeasure20":"","strSource":"https://www.bbc.co.uk/food/recipes/beef_and_mustard_pie_58002","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"52938","strMeal":"Jamaican Beef Patties","strMealAlternate":null,"strCategory":"Beef","strArea":"Jamaican","strInstructions":"Make the Pastry Dough\r\n\r\nTo a large bowl, add flour, 1 teaspoon salt, and turmeric and mix thoroughly.\r\nRub shortening into flour until there are small pieces of shortening completely covered with flour.\r\nPour in 1/2 cup of the ice water and mix with your hands to bring the dough together. Keep adding ice water 2 to 3 tablespoons at a time until the mixture forms a dough.\r\nAt this stage, you can cut the dough into 2 large pieces, wrap in plastic and refrigerate for 30 minutes before using it.\r\nAlternatively, cut the dough into 10 to 12 equal pieces, place on a platter or baking sheet, cover securely with plastic wrap and let chill for 30 minutes while you make the filling.\r\nMake the Filling\r\n\r\nAdd ground beef to a large bowl. Sprinkle in allspice and black pepper. Mix together and set aside.\r\nHeat oil in a skillet until hot.\r\nAdd onions and sauté until translucent. Add hot pepper, garlic and thyme and continue to sauté for another minute. Add 1/4 teaspoon salt.\r\nAdd seasoned ground beef and toss to mix, breaking up any clumps, and let cook until the meat is no longer pink.\r\nAdd ketchup and more salt to taste.\r\nPour in 2 cups of water and stir. Bring the mixture to a boil then reduce heat and let simmer until most of the liquid has evaporated and whatever is remaining has reduced to a thick sauce.\r\nFold in green onions. Remove from heat and let cool completely.\r\nAssemble the Patties\r\n\r\nBeat the egg and water together to make an egg wash. Set aside.\r\nNow you can prepare the dough in two ways.\r\nFirst Method: Flour the work surface and rolling pin. If you had cut it into 2 large pieces, then take one of the large pieces and roll it out into a very large circle. Take a bowl with a wide rim (about 5 inches) and cut out three circles.\r\n\r\nPlace about 3 heaping tablespoons of the filling onto 1/2 of each circle. Dip a finger into the water and moisten the edges of the pastry. Fold over the other half and press to seal. \r\n\r\nTake a fork and crimp the edges. Cut off any extra to make it look neat and uniform. Place on a parchment-lined baking sheet and continue to work until you have rolled all the dough and filled the patties.\r\nSecond Method: If you had pre-cut the dough into individual pieces, work with one piece of dough at a time. Roll it out on a floured surface into a 5-inch circle or a little larger. Don’t worry if the edges are not perfect.\r\n\r\nPlace 3 heaping tablespoons of the filling on one side of the circle. Dip a finger into the water and moisten the edges of the pastry. Fold over the other half and press to seal.\r\n\r\nTake a fork and crimp the edges. Cut off any extra to make it look neat and uniform. Place on a parchment-lined baking sheet and continue work until you have rolled all the dough and filled the patties.\r\n\r\nFrying and Serving the Patties\r\n\r\nAfter forming the patties, place the pans in the refrigerator while you heat the oven to 350 F.\r\nJust before adding the pans with the patties to the oven, brush the patties with egg wash.\r\nBake patties for 30 minutes or until golden brown.\r\nCool on wire racks.\r\nServe warm.","strMealThumb":"https://www.themealdb.com/images/media/meals/wsqqsw1515364068.jpg","strTags":"Snack,Spicy","strYoutube":"https://www.youtube.com/watch?v=ypQjoiZiTac","strIngredient1":"Plain Flour","strIngredient2":"Salt","strIngredient3":"Curry Powder","strIngredient4":"Butter","strIngredient5":"Water","strIngredient6":"Minced Beef","strIngredient7":"Allspice","strIngredient8":"Black Pepper","strIngredient9":"Vegetable Oil","strIngredient10":"Onions","strIngredient11":"Red Pepper","strIngredient12":"Garlic","strIngredient13":"Thyme","strIngredient14":"Salt","strIngredient15":"Tomato Ketchup","strIngredient16":"Water","strIngredient17":"Onions","strIngredient18":"Egg","strIngredient19":"Water","strIngredient20":"Water","strMeasure1":"4 cups ","strMeasure2":"1 tsp ","strMeasure3":"1 tsp ","strMeasure4":"250g","strMeasure5":"1 cup ","strMeasure6":"900g","strMeasure7":"1 tsp ","strMeasure8":"1/2 tsp","strMeasure9":"2 tbs","strMeasure10":"1 cup ","strMeasure11":"Ground","strMeasure12":"2 tsp ground","strMeasure13":"1 tbs","strMeasure14":"1/4 tsp","strMeasure15":"2 tbs","strMeasure16":"2 cups ","strMeasure17":"1/2 cup ","strMeasure18":"1 beaten","strMeasure19":"1 tbs","strMeasure20":"1/4 cup","strSource":"https://www.thespruce.com/jamaican-beef-patties-recipe-2137762","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null},{"idMeal":"53109","strMeal":"Mini chilli beef pies","strMealAlternate":null,"strCategory":"Beef","strArea":"Australian","strInstructions":"step 1\r\nTo make chilli, heat oil in a pan and fry onion for 5 mins until soft. Add spices; fry for 1 min. Stir in beef and cook for a few mins. Add tomato purée, stock and cinnamon. Give it a stir, bring to the boil, then simmer for 15-20 mins until very little liquid is left. Add beans 5 mins before the end of cooking. Check seasoning and cool.\r\n\r\nstep 2\r\nHeat oven to 200C/fan 180C/gas 6. Using a 7cm pastry cutter, stamp out 12 circles from the pastry. Use to line a 12-hole mini muffin tray, prick the base of the pastry with a fork, and bake for 10 mins. Remove from oven and cool on a wire tray. Repeat with remaining pastry.\r\n\r\nstep 3\r\nMeanwhile, cook the potato in boiling water until tender. Drain, mash with soured cream and seasoning, then stir through chives. Spoon 1-2 tsp of chilli mix into the pastry cases and top with a tsp of mash. Ruffle mash with a fork; return to the oven for 15 mins or until golden.","strMealThumb":"https://www.themealdb.com/images/media/meals/6sarfo1762340107.jpg","strTags":null,"strYoutube":"https://www.youtube.com/watch?v=PHuU1L92-Ns","strIngredient1":"Ready rolled shortcrust pastry","strIngredient2":"Sunflower Oil","strIngredient3":"Onion","strIngredient4":"Hot Chilli Powder","strIngredient5":"Ground Cumin","strIngredient6":"Minced Beef","strIngredient7":"Tomato Puree","strIngredient8":"Beef Stock","strIngredient9":"Ground Cinnamon","strIngredient10":"Kidney Beans","strIngredient11":"Potatoes","strIngredient12":"Sour Cream","strIngredient13":"Chopped Chive","strIngredient14":"","strIngredient15":"","strIngredient16":"","strIngredient17":"","strIngredient18":"","strIngredient19":"","strIngredient20":"","strMeasure1":"450g","strMeasure2":"1 tablespoon","strMeasure3":"1 small","strMeasure4":"2 tsp","strMeasure5":"2 tsp","strMeasure6":"250g","strMeasure7":"85g","strMeasure8":"150ml","strMeasure9":"Pinch","strMeasure10":"200g","strMeasure11":"1 large","strMeasure12":"3  tablespoons","strMeasure13":"2 tablespoons","strMeasure14":" ","strMeasure15":" ","strMeasure16":" ","strMeasure17":" ","strMeasure18":" ","strMeasure19":" ","strMeasure20":" ","strSource":"https://www.bbcgoodfood.com/recipes/mini-chilli-beef-pies","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":"2025-11-05 04:21:51"},{"idMeal":"52812","strMeal":"Beef Brisket Pot Roast","strMealAlternate":null,"strCategory":"Beef","strArea":"American","strInstructions":"1 Prepare the brisket for cooking: On one side of the brisket there should be a layer of fat, which you want. If there are any large chunks of fat, cut them off and discard them. Large pieces of fat will not be able to render out completely.\r\nUsing a sharp knife, score the fat in parallel lines, about 3/4-inch apart. Slice through the fat, not the beef. Repeat in the opposite direction to make a cross-hatch pattern.\r\nSalt the brisket well and let it sit at room temperature for 30 minutes.\r\n \r\n2 Sear the brisket: You'll need an oven-proof, thick-bottomed pot with a cover, or Dutch oven, that is just wide enough to hold the brisket roast with a little room for the onions.\r\nPat the brisket dry and place it, fatty side down, into the pot and place it on medium high heat. Cook for 5-8 minutes, lightly sizzling, until the fat side is nicely browned. (If the roast seems to be cooking too fast, turn the heat down to medium. You want a steady sizzle, not a raging sear.)\r\nTurn the brisket over and cook for a few minutes more to brown the other side.\r\n\r\n3 Sauté the onions and garlic: When the brisket has browned, remove it from the pot and set aside. There should be a couple tablespoons of fat rendered in the pot, if not, add some olive oil.\r\nAdd the chopped onions and increase the heat to high. Sprinkle a little salt on the onions. Sauté, stirring often, until the onions are lightly browned, 5-8 minutes. Stir in the garlic and cook 1-2 more minutes.\r\n \r\n4 Return brisket to pot, add herbs, stock, bring to simmer, cover, cook in oven: Preheat the oven to 300°F. Use kitchen twine to tie together the bay leaves, rosemary and thyme.\r\nMove the onions and garlic to the sides of the pot and nestle the brisket inside. Add the beef stock and the tied-up herbs. Bring the stock to a boil on the stovetop.\r\nCover the pot, place the pot in the 300°F oven and cook for 3 hours. Carefully flip the brisket every hour so it cooks evenly.\r\n \r\n5 Add carrots, continue to cook: After 3 hours, add the carrots. Cover the pot and cook for 1 hour more, or until the carrots are cooked through and the brisket is falling-apart tender.\r\n6 Remove brisket to cutting board, tent with foil: When the brisket is falling-apart tender, take the pot out of the oven and remove the brisket to a cutting board. Cover it with foil. Pull out and discard the herbs.\r\n7 Make sauce (optional): At this point you have two options. You can serve as is, or you can make a sauce with the drippings and some of the onions. If you serve as is, skip this step.\r\nTo make a sauce, remove the carrots and half of the onions, set aside and cover them with foil. Pour the ingredients that are remaining into the pot into a blender, and purée until smooth. If you want, add 1 tablespoon of mustard to the mix. Put into a small pot and keep warm.\r\n8 Slice the meat across the grain: Notice the lines of the muscle fibers of the roast. This is the \"grain\" of the meat. Slice the meat perpendicular to these lines, or across the grain (cutting this way further tenderizes the meat), in 1/4-inch to 1/2-inch slices.\r\nServe with the onions, carrots and gravy. Serve with mashed, roasted or boiled potatoes, egg noodles or polenta.","strMealThumb":"https://www.themealdb.com/images/media/meals/ursuup1487348423.jpg","strTags":"Meat","strYoutube":"https://www.youtube.com/watch?v=gh48wM6bPWQ","strIngredient1":"Beef Brisket","strIngredient2":"Salt","strIngredient3":"Onion","strIngredient4":"Garlic","strIngredient5":"Thyme","strIngredient6":"Rosemary","strIngredient7":"Bay Leaves","strIngredient8":"beef stock","strIngredient9":"Carrots","strIngredient10":"Mustard","strIngredient11":"Potatoes","strIngredient12":null,"strIngredient13":null,"strIngredient14":null,"strIngredient15":null,"strIngredient16":null,"strIngredient17":null,"strIngredient18":null,"strIngredient19":null,"strIngredient20":null,"strMeasure1":"4-5 pound","strMeasure2":"Dash","strMeasure3":"3","strMeasure4":"5 cloves","strMeasure5":"1 Sprig","strMeasure6":"1 sprig ","strMeasure7":"4","strMeasure8":"2 cups","strMeasure9":"3 Large","strMeasure10":"1 Tbsp","strMeasure11":"4 Mashed","strMeasure12":"","strMeasure13":"","strMeasure14":"","strMeasure15":"","strMeasure16":"","strMeasure17":"","strMeasure18":"","strMeasure19":"","strMeasure20":"","strSource":"http://www.simplyrecipes.com/recipes/beef_brisket_pot_roast/","strImageSource":null,"strCreativeCommonsConfirmed":null,"dateModified":null}]

class MealDbapi {
  MealDbapi({List<Meals>? meals}) {
    _meals = meals;
  }

  MealDbapi.fromJson(dynamic json) {
    if (json['meals'] != null) {
      _meals = [];
      json['meals'].forEach((v) {
        _meals?.add(Meals.fromJson(v));
      });
    }
  }
  List<Meals>? _meals;
  MealDbapi copyWith({List<Meals>? meals}) => MealDbapi(meals: meals ?? _meals);
  List<Meals>? get meals => _meals;

  Map<String, dynamic> toJson() {
    final map = <String, dynamic>{};
    if (_meals != null) {
      map['meals'] = _meals?.map((v) => v.toJson()).toList();
    }
    return map;
  }
}

/// idMeal : "53238"
/// strMeal : "Beef pho"
/// strMealAlternate : null
/// strCategory : "Beef"
/// strArea : "Vietnamese"
/// strInstructions : "step 1\r\nTip the beef stock along with 500ml of water into a large saucepan. Sit the onion and ginger in a frying pan over a high heat and char on all sides, around 3-5 mins (you can also do this under your grill). Once charred, add to the beef stock. In the same pan, toast the spices for 2-3 mins and once they begin to smell fragrant, add them to the beef stock as well. Bring the stock to the boil, then turn to a simmer and cook for 30mins before straining.\r\n\r\nstep 2\r\nMeanwhile, cut the fat from the steak and wrap in cling film, then put into the freezer for 15 mins – this will make your steak really easy to slice! Slice it thinly, then cover with cling film again and pop into the fridge.\r\n\r\nstep 3\r\nTaste the beef stock and use the palm sugar, fish sauce and soy to season. Cook the noodles according to package instructions and split between two bowls, topping each with the sliced beef. Bring the stock to the boil and then pour into the bowls (the heat will cook the beef). Top each with the spring onions, chilli slices and herbs. Serve with the lime wedges to squeeze over."
